class MagixFormTools{constructor(){this.initUrlLocks()}initUrlLocks(){document.addEventListener("click",(t=>{const e=t.target.closest(".toggle-url-lock");if(!e)return;t.preventDefault();const l=e.getAttribute("data-target"),r=document.getElementById(l),s=e.querySelector("i");r&&(r.hasAttribute("readonly")?(r.removeAttribute("readonly"),r.classList.remove("bg-light"),s.classList.replace("bi-lock","bi-unlock"),s.classList.add("text-warning"),e.setAttribute("title","Verrouiller l'URL"),r.focus()):(r.setAttribute("readonly","readonly"),r.classList.add("bg-light"),s.classList.replace("bi-unlock","bi-lock"),s.classList.remove("text-warning"),e.setAttribute("title","Déverrouiller l'URL")))}))}}document.addEventListener("DOMContentLoaded",(()=>new MagixFormTools));